//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Footnote/endnote numbering, restart, placement; doc-wide vs
//! section-wide precedence".
//!
//! Each `#[test]` encodes one declarative TestSpec mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 / MS-OE376. A FAILING assertion here is a real
//! Word-compliance gap in the stemma engine (the markup stemma actively
//! generates / restructures diverges from what Word requires, OR a value Word
//! honours is not preserved / does not open clean). It is NOT something to make
//! pass by weakening the test.
//!
//! Methodology guard (consumption vs. save): stemma round-trips UNTOUCHED
//! content byte-verbatim, so `reserialize()` of an unedited doc reflects
//! stemma's verbatim-preservation contract, not Word's render-time
//! normalization. The `xml*` assertions below only target markup stemma
//! ACTIVELY rebuilds: section-level `w:footnotePr` / `w:endnotePr` are parsed
//! into a typed NoteProperties model and re-emitted via the serializer, so
//! child ORDERING (CT_FtnProps / CT_EdnProps schema sequence) and structural
//! validity are legitimate serializer assertions. We never assert that a
//! consumption-only remap (e.g. Word treating pos=sectEnd like beneathText)
//! appears in the saved XML.

use std::io::{Cursor, Read, Write};

use stemma::ExportOptions;
use stemma::api::{Document, validate};
use zip::write::FileOptions;

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. `extra_parts` is a list of
/// `(part_name, xml)` (e.g. `("word/styles.xml", "…")`) — each gets a
/// `[Content_Types].xml` override based on a small known map.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type override for each known extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let ct = match *part {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            "word/footnotes.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.footnotes+xml"
            }
            "word/endnotes.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.endnotes+xml"
            }
            other => panic!("make_docx: no content-type mapping for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // document.xml.rels: add a relationship for each extra part so refs resolve.
    let mut doc_rel_entries = String::new();
    for (i, (part, _)) in extra_parts.iter().enumerate() {
        let rel_type = match *part {
            "word/styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            "word/numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            "word/footnotes.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/footnotes"
            }
            "word/endnotes.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/endnotes"
            }
            other => panic!("make_docx: no relationship-type mapping for extra part {other}"),
        };
        // Target is relative to word/.
        let target = part.strip_prefix("word/").unwrap_or(part);
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` of a `.docx`.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse -> serialize(ExportOptions::default()) -> document.xml string.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Whitespace-tolerant ordered-substring match (the regex crate is unavailable
/// in the daily build). The spec regexes here are all of the shape
/// `<w:a .../>\s*<w:b .../>\s*…` — adjacent self-closing elements separated
/// only by optional whitespace. We collapse all whitespace that sits strictly
/// between a `>` and the next `<`, then check that the concatenated `needles`
/// appear contiguously in the collapsed haystack.
fn contains_ordered_adjacent(xml: &str, needles: &[&str]) -> bool {
    let collapsed = collapse_intertag_ws(xml);
    let joined = needles.join("");
    collapsed.contains(&joined)
}

/// Remove whitespace runs that occur between a `>` and the next `<`.
fn collapse_intertag_ws(xml: &str) -> String {
    let bytes = xml.as_bytes();
    let mut out = String::with_capacity(xml.len());
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i] as char;
        if c == '>' {
            out.push('>');
            i += 1;
            let mut j = i;
            while j < bytes.len() && (bytes[j] as char).is_whitespace() {
                j += 1;
            }
            if j < bytes.len() && bytes[j] as char == '<' {
                i = j; // drop the inter-tag whitespace
            }
            continue;
        }
        out.push(c);
        i += 1;
    }
    out
}

/// Assert opens-clean: the validator reports no issues.
fn assert_opens_clean(bytes: &[u8], rule: &str, refs: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule} — {refs}; expected the document to open clean (no validator errors), but got: {:?}",
        report.issues
    );
}

