#[ignore = "open question: WORD-COMPLIANCE GAP — section-wide footnotePr children are re-serialized in authored order, not CT_FtnProps schema order (pos -> numFmt -> numStart -> numRestart); out-of-order footnotePr is schema-invalid and triggers Word repair (ECMA-376 §17.11.11; §17.11.21; ISO 29500-1 Annex A CT_FtnProps)"]
#[test]
fn sect_footnotepr_children_emitted_in_ct_ftnprops_order() {
    let refs = "ECMA-376 §17.18.74; §17.11.21; ISO 29500-1 Annex A CT_FtnProps; §17.11.11";
    let rule = "section-wide footnotePr children must serialize in CT_FtnProps order pos -> numFmt -> numStart -> numRestart (EG_FtnEdnNumProps = numStart then numRestart), regardless of authored order";
    let body = r#"<w:p><w:r><w:t>Body paragraph with a footnote anchor.</w:t></w:r></w:p><w:sectPr><w:footnotePr><w:numRestart w:val="eachSect"/><w:numStart w:val="2"/><w:numFmt w:val="lowerRoman"/><w:pos w:val="beneathText"/></w:footnotePr></w:sectPr>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        contains_ordered_adjacent(
            &xml,
            &[
                "<w:pos",
                " w:val=\"beneathText\"/><w:numFmt",
                " w:val=\"lowerRoman\"/><w:numStart",
                " w:val=\"2\"/><w:numRestart",
                " w:val=\"eachSect\"/>",
            ]
        ),
        "{rule} — {refs}; expected CT_FtnProps sequence <w:pos/> <w:numFmt/> <w:numStart/> <w:numRestart/> (whitespace-tolerant translation of regex `<w:pos[^>]*/>\\s*<w:numFmt[^>]*/>\\s*<w:numStart[^>]*/>\\s*<w:numRestart[^>]*/>`), got: {xml}"
    );

    assert_opens_clean(&b, rule, refs);
}

