    let body = r#"<w:p><w:r><w:t>Body text with a footnote reference.</w:t></w:r></w:p><w:sectPr><w:footnotePr><w:pos w:val="beneathText"/><w:numFmt w:val="lowerRoman"/><w:numStart w:val="2"/><w:numRestart w:val="eachSect"/></w:footnotePr></w:sectPr>"#;
